SELECT 1;
create table activity_logs (created_at timestamp(6) with time zone not null, actor_id uuid, entity_id uuid, id uuid not null, repository_id uuid, action varchar(80) not null, entity_type varchar(80) not null, description TEXT, metadata jsonb not null, primary key (id));
create table attachments (created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, size_bytes bigint not null, id uuid not null, target_id uuid, uploaded_by_id uuid, storage_provider varchar(50) not null, checksum_sha256 varchar(64), target_type varchar(80), mime_type varchar(120), original_filename varchar(255) not null, storage_key TEXT, stored_filename varchar(255), primary key (id));
create table branch_commits (committed_at timestamp(6) with time zone not null, created_at timestamp(6) with time zone not null, branch_id uuid not null, commit_id uuid not null, id uuid not null, repository_id uuid not null, primary key (id), constraint uk_branch_commits_branch_commit unique (branch_id, commit_id));
create table branch_protection_rules (allows_deletions boolean not null, allows_force_pushes boolean not null, required_approvals integer not null, requires_pull_request_review boolean not null, requires_status_checks boolean not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, created_by_id uuid, id uuid not null, repository_id uuid not null, branch_name_pattern varchar(160) not null, settings jsonb not null, primary key (id), constraint uk_branch_protection_rules_repository_pattern unique (repository_id, branch_name_pattern));
create table branches (is_default boolean not null, is_protected boolean not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, created_by_id uuid, created_from_branch_id uuid, head_commit_id uuid, id uuid not null, repository_id uuid not null, name varchar(120) not null, primary key (id), constraint uk_branches_repository_name unique (repository_id, name));
create table commit_file_changes (additions integer not null, deletions integer not null, diff_hunk_count integer not null, created_at timestamp(6) with time zone not null, commit_id uuid not null, id uuid not null, repository_id uuid not null, source_file_id uuid, change_type varchar(20) not null check ((change_type in ('CREATED','UPDATED','DELETED','RENAMED','MOVED'))), new_file_mode varchar(20), old_file_mode varchar(20), new_content_sha256 varchar(64), old_content_sha256 varchar(64), new_blob_hash varchar(80), old_blob_hash varchar(80), new_path TEXT, old_path TEXT, patch_storage_key TEXT, primary key (id));
create table commit_parents (parent_order integer not null, commit_id uuid not null, id uuid not null, parent_commit_id uuid not null, repository_id uuid not null, primary key (id), constraint uk_commit_parents_commit_parent unique (commit_id, parent_commit_id), constraint uk_commit_parents_commit_order unique (commit_id, parent_order));
create table commit_statuses (completed_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, started_at timestamp(6) with time zone, commit_id uuid not null, creator_id uuid, id uuid not null, repository_id uuid not null, state varchar(20) not null check ((state in ('PENDING','SUCCESS','FAILURE','ERROR'))), context varchar(160) not null, description TEXT, target_url TEXT, primary key (id), constraint uk_commit_statuses_repository_commit_context unique (repository_id, commit_id, context));
create table commits (authored_at timestamp(6) with time zone, committed_at timestamp(6) with time zone not null, created_at timestamp(6) with time zone not null, author_id uuid, id uuid not null, repository_id uuid not null, commit_hash varchar(80) not null, tree_hash varchar(80), author_name varchar(160), committer_name varchar(160), author_email varchar(255), committer_email varchar(255), message TEXT not null, primary key (id), constraint uk_commits_repository_hash unique (repository_id, commit_hash));
create table contribution_days (comment_count integer not null, commit_count integer not null, contribution_date date not null, issue_count integer not null, other_count integer not null, private_count integer not null, public_count integer not null, pull_request_count integer not null, release_count integer not null, repository_count integer not null, review_count integer not null, total_count integer not null, created_at timestamp(6) with time zone not null, id uuid not null, user_id uuid not null, primary key (id), constraint uk_contribution_days_user_date unique (user_id, contribution_date));
create table contribution_events (contribution_date date not null, is_ignored boolean not null, weight integer not null, created_at timestamp(6) with time zone not null, occurred_at timestamp(6) with time zone not null, id uuid not null, repository_id uuid, source_id uuid not null, user_id uuid not null, visibility varchar(20) not null check ((visibility in ('PUBLIC','PRIVATE'))), contribution_type varchar(60) not null check ((contribution_type in ('COMMIT_CREATED','ISSUE_OPENED','ISSUE_CLOSED','PULL_REQUEST_OPENED','PULL_REQUEST_MERGED','PULL_REQUEST_REVIEWED','ISSUE_COMMENT_CREATED','PULL_REQUEST_COMMENT_CREATED','REPOSITORY_CREATED','RELEASE_PUBLISHED','OTHER'))), source_type varchar(80) not null, metadata jsonb not null, primary key (id), constraint uk_contribution_events_source unique (user_id, contribution_type, source_type, source_id));
create table email_verification_tokens (created_at timestamp(6) with time zone not null, expires_at timestamp(6) with time zone not null, verified_at timestamp(6) with time zone, id uuid not null, user_id uuid not null, token_hash varchar(255) not null, primary key (id), constraint uk_email_verification_tokens_token_hash unique (token_hash));
create table file_versions (created_at timestamp(6) with time zone not null, size_bytes bigint not null, commit_id uuid not null, id uuid not null, repository_id uuid not null, source_file_id uuid, file_mode varchar(20), content_sha256 varchar(64), blob_hash varchar(80), object_storage_key TEXT, path TEXT not null, primary key (id), constraint uk_file_versions_commit_path unique (commit_id, path));
create table issue_assignees (assigned_at timestamp(6) with time zone not null, assigned_by_id uuid, id uuid not null, issue_id uuid not null, user_id uuid not null, primary key (id), constraint uk_issue_assignees_issue_user unique (issue_id, user_id));
create table issue_comments (created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, edited_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, author_id uuid, id uuid not null, issue_id uuid not null, parent_comment_id uuid, body TEXT not null, primary key (id));
create table issue_label_links (id uuid not null, issue_id uuid not null, label_id uuid not null, primary key (id), constraint uk_issue_label_links_issue_label unique (issue_id, label_id));
create table issue_labels (created_at timestamp(6) with time zone not null, created_by_id uuid, id uuid not null, repository_id uuid not null, color varchar(20) not null, name varchar(80) not null, description TEXT, primary key (id), constraint uk_issue_labels_repository_name unique (repository_id, name));
create table issues (issue_number integer not null, closed_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, author_id uuid, closed_by_id uuid, id uuid not null, milestone_id uuid, repository_id uuid not null, status varchar(20) not null check ((status in ('OPEN','CLOSED'))), state_reason varchar(50), body TEXT, title varchar(255) not null, primary key (id), constraint uk_issues_repository_number unique (repository_id, issue_number));
create table milestones (closed_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, due_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, created_by_id uuid, id uuid not null, repository_id uuid not null, status varchar(20) not null check ((status in ('OPEN','CLOSED'))), title varchar(160) not null, description TEXT, primary key (id), constraint uk_milestones_repository_title unique (repository_id, title));
create table notifications (is_read boolean not null, created_at timestamp(6) with time zone not null, read_at timestamp(6) with time zone, actor_id uuid, id uuid not null, issue_id uuid, pull_request_id uuid, recipient_id uuid not null, repository_id uuid, type varchar(80) not null, message TEXT, target_url TEXT, title varchar(255) not null, metadata jsonb not null, primary key (id));
create table organization_members (joined_at timestamp(6) with time zone not null, removed_at timestamp(6) with time zone, id uuid not null, invited_by_id uuid, organization_id uuid not null, user_id uuid not null, role varchar(30) not null check ((role in ('OWNER','MEMBER'))), primary key (id), constraint uk_organization_members_organization_user unique (organization_id, user_id));
create table organizations (created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, created_by_id uuid, id uuid not null, slug varchar(100) not null, location varchar(120), display_name varchar(160) not null, avatar_url TEXT, billing_email varchar(255), description TEXT, website_url TEXT, primary key (id), constraint uk_organizations_slug unique (slug));
create table password_reset_tokens (created_at timestamp(6) with time zone not null, expires_at timestamp(6) with time zone not null, used_at timestamp(6) with time zone, id uuid not null, user_id uuid not null, token_hash varchar(255) not null, primary key (id), constraint uk_password_reset_tokens_token_hash unique (token_hash));
create table pull_request_comments (is_resolved boolean not null, line_number integer, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, edited_at timestamp(6) with time zone, resolved_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, author_id uuid, id uuid not null, parent_comment_id uuid, pull_request_id uuid not null, resolved_by_id uuid, source_file_id uuid, comment_type varchar(20) not null check ((comment_type in ('GENERAL','INLINE'))), diff_side varchar(20) check ((diff_side in ('LEFT','RIGHT'))), body TEXT not null, file_path TEXT, primary key (id));
create table pull_request_commits (commit_id uuid not null, id uuid not null, pull_request_id uuid not null, primary key (id), constraint uk_pull_request_commits_pull_request_commit unique (pull_request_id, commit_id));
create table pull_request_file_changes (additions integer not null, deletions integer not null, diff_hunk_count integer not null, created_at timestamp(6) with time zone not null, id uuid not null, pull_request_id uuid not null, repository_id uuid not null, source_file_id uuid, change_type varchar(20) not null check ((change_type in ('CREATED','UPDATED','DELETED','RENAMED','MOVED'))), new_blob_hash varchar(80), old_blob_hash varchar(80), new_path TEXT, old_path TEXT, patch_storage_key TEXT, primary key (id));
create table pull_request_review_requests (created_at timestamp(6) with time zone not null, fulfilled_at timestamp(6) with time zone, removed_at timestamp(6) with time zone, id uuid not null, pull_request_id uuid not null, requested_by_id uuid, reviewer_id uuid not null, reviewer_type varchar(20) not null check ((reviewer_type in ('USER','TEAM'))), primary key (id), constraint uk_pull_request_review_requests_reviewer unique (pull_request_id, reviewer_type, reviewer_id));
create table pull_request_reviews (dismissed_at timestamp(6) with time zone, submitted_at timestamp(6) with time zone not null, dismissed_by_id uuid, id uuid not null, pull_request_id uuid not null, reviewer_id uuid not null, status varchar(30) not null check ((status in ('COMMENTED','APPROVED','CHANGES_REQUESTED'))), body TEXT, dismiss_reason TEXT, primary key (id));
create table pull_requests (pull_request_number integer not null, closed_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, merged_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, author_id uuid, closed_by_id uuid, id uuid not null, merge_commit_id uuid, merged_by_id uuid, milestone_id uuid, repository_id uuid not null, source_branch_id uuid not null, target_branch_id uuid not null, status varchar(20) not null check ((status in ('DRAFT','OPEN','MERGED','CLOSED'))), body TEXT, title varchar(255) not null, primary key (id), constraint uk_pull_requests_repository_number unique (repository_id, pull_request_number));
create table reactions (created_at timestamp(6) with time zone not null, id uuid not null, target_id uuid not null, user_id uuid not null, emoji varchar(40) not null, target_type varchar(80) not null, primary key (id), constraint uk_reactions_user_target_emoji unique (user_id, target_type, target_id, emoji));
create table refresh_tokens (created_at timestamp(6) with time zone not null, expires_at timestamp(6) with time zone not null, revoked_at timestamp(6) with time zone, id uuid not null, user_id uuid not null, ip_address varchar(64), device_info TEXT, token_hash varchar(255) not null, user_agent TEXT, primary key (id), constraint uk_refresh_tokens_token_hash unique (token_hash));
create table repositories (forks_count integer not null, is_template boolean not null, issues_count integer not null, next_issue_number integer not null, next_pull_request_number integer not null, pull_requests_count integer not null, stars_count integer not null, archived_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, forked_from_repository_id uuid, id uuid not null, owner_id uuid not null, readme_file_id uuid, status varchar(20) not null check ((status in ('ACTIVE','ARCHIVED','DELETED'))), visibility varchar(20) not null check ((visibility in ('PUBLIC','PRIVATE','INTERNAL'))), owner_type varchar(30) not null check ((owner_type in ('USER','ORGANIZATION'))), default_branch_name varchar(120) not null, name varchar(120) not null, slug varchar(140) not null, description TEXT, primary key (id), constraint uk_repositories_owner_slug unique (owner_type, owner_id, slug));
create table repository_forks (created_at timestamp(6) with time zone not null, fork_repository_id uuid not null, forked_by_id uuid not null, id uuid not null, source_repository_id uuid not null, primary key (id), constraint uk_repository_forks_source_fork unique (source_repository_id, fork_repository_id));
create table repository_invitations (accepted_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, expires_at timestamp(6) with time zone not null, revoked_at timestamp(6) with time zone, id uuid not null, invited_by_id uuid, invited_user_id uuid, repository_id uuid not null, role varchar(30) not null check ((role in ('OWNER','MAINTAINER','CONTRIBUTOR','VIEWER'))), invited_email varchar(255), token_hash varchar(255) not null, primary key (id), constraint uk_repository_invitations_token_hash unique (token_hash));
create table repository_members (joined_at timestamp(6) with time zone not null, removed_at timestamp(6) with time zone, id uuid not null, invited_by_id uuid, repository_id uuid not null, user_id uuid not null, role varchar(30) not null check ((role in ('OWNER','MAINTAINER','CONTRIBUTOR','VIEWER'))), primary key (id), constraint uk_repository_members_repository_user unique (repository_id, user_id));
create table repository_releases (is_prerelease boolean not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, published_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, author_id uuid, id uuid not null, repository_id uuid not null, tag_id uuid, status varchar(20) not null check ((status in ('DRAFT','PUBLISHED'))), tag_name varchar(120) not null, name varchar(160) not null, body TEXT, primary key (id), constraint uk_repository_releases_repository_tag unique (repository_id, tag_name));
create table repository_stars (created_at timestamp(6) with time zone not null, id uuid not null, repository_id uuid not null, user_id uuid not null, primary key (id), constraint uk_repository_stars_repository_user unique (repository_id, user_id));
create table repository_tags (created_at timestamp(6) with time zone not null, commit_id uuid not null, id uuid not null, repository_id uuid not null, tagged_by_id uuid, name varchar(120) not null, message TEXT, primary key (id), constraint uk_repository_tags_repository_name unique (repository_id, name));
create table repository_watches (created_at timestamp(6) with time zone not null, id uuid not null, repository_id uuid not null, user_id uuid not null, notification_level varchar(30) not null check ((notification_level in ('PARTICIPATING','ALL','IGNORE'))), primary key (id), constraint uk_repository_watches_repository_user unique (repository_id, user_id));
create table repository_webhooks (is_active boolean not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, last_delivered_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, created_by_id uuid, id uuid not null, repository_id uuid not null, content_type varchar(40) not null, secret_hash varchar(255), url TEXT not null, events jsonb not null, primary key (id), constraint uk_repository_webhooks_repository_url unique (repository_id, url));
create table source_files (is_binary boolean not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, size_bytes bigint not null, updated_at timestamp(6) with time zone not null, branch_id uuid not null, created_by_id uuid, id uuid not null, parent_id uuid, repository_id uuid not null, updated_by_id uuid, file_type varchar(20) not null check ((file_type in ('FILE','FOLDER'))), extension varchar(50), content_sha256 varchar(64), blob_hash varchar(80), mime_type varchar(120), name varchar(255) not null, object_storage_key TEXT, path TEXT not null, primary key (id), constraint uk_source_files_branch_path unique (branch_id, path));
create table team_members (joined_at timestamp(6) with time zone not null, removed_at timestamp(6) with time zone, added_by_id uuid, id uuid not null, team_id uuid not null, user_id uuid not null, role varchar(30) not null check ((role in ('MAINTAINER','MEMBER'))), primary key (id), constraint uk_team_members_team_user unique (team_id, user_id));
create table team_repositories (created_at timestamp(6) with time zone not null, added_by_id uuid, id uuid not null, repository_id uuid not null, team_id uuid not null, role varchar(30) not null check ((role in ('OWNER','MAINTAINER','CONTRIBUTOR','VIEWER'))), primary key (id), constraint uk_team_repositories_team_repository unique (team_id, repository_id));
create table teams (created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, id uuid not null, organization_id uuid not null, parent_team_id uuid, privacy varchar(30) not null check ((privacy in ('VISIBLE','SECRET'))), name varchar(120) not null, slug varchar(140) not null, description TEXT, primary key (id), constraint uk_teams_organization_slug unique (organization_id, slug));
create table user_follows (created_at timestamp(6) with time zone not null, follower_id uuid not null, following_id uuid not null, id uuid not null, primary key (id), constraint uk_user_follows_follower_following unique (follower_id, following_id));
create table users (is_verified boolean not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, last_active_at timestamp(6) with time zone, last_login_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, verified_at timestamp(6) with time zone, id uuid not null, status varchar(30) not null check ((status in ('ACTIVE','INACTIVE','SUSPENDED','BANNED','DELETED'))), username varchar(50) not null, company varchar(120), display_name varchar(120), location varchar(120), avatar_url TEXT, bio TEXT, email varchar(255) not null, password_hash varchar(255) not null, website_url TEXT, primary key (id), constraint uk_users_username unique (username), constraint uk_users_email unique (email));
